        _INTERPOLATION_RESULT = interpolationResult ?? INTERPOLATION_RESULT;

  /// Finish building, and store into the [fbBuilder].
  @override
  int finish(fb.Builder fbBuilder) {
    final int? INTERPOLATION_REQUESTOffset = _INTERPOLATION_REQUEST?.getOrCreateOffset(fbBuilder);
    final int? INTERPOLATION_RESULTOffset = _INTERPOLATION_RESULT?.getOrCreateOffset(fbBuilder);
    fbBuilder.startTable(2);
    fbBuilder.addOffset(0, INTERPOLATION_REQUESTOffset);
    fbBuilder.addOffset(1, INTERPOLATION_RESULTOffset);
    return fbBuilder.endTable();
  }

  /// Convenience method to serialize to byte list.
  @override
  Uint8List toBytes([String? fileIdentifier]) {
    final fbBuilder = fb.Builder(deduplicateTables: false);
    fbBuilder.finish(finish(fbBuilder), fileIdentifier);
    return fbBuilder.buffer;
  }
}
